sql:
SELECT MAX(setting_value) AS max_inventory_setting
FROM system_settings
WHERE setting_name = 'max_inventory_level';

SELECT part_model, weight, thermal_dissipation
FROM hardware_parts
WHERE thermal_dissipation > 60;

SELECT part_model, manufacturer, AVG(thermal_dissipation) AS avg_thermal_dissipation
FROM hardware_parts
GROUP BY part_model, manufacturer;

SELECT MAX(weight) AS max_weight
FROM hardware_parts
WHERE manufacturer = 'Intel' AND product_line IN ('Data Center', 'Enterprise');

external_knowledge:
- A 'tested' compatibility status refers to hardware parts that have undergone compatibility testing with other parts; 
- Packet buffer size is a measure of the capacity of a hardware part's buffer to store packets of data; 
- Quantity in stock refers to the number of units of a part available in the inventory.

sql:
SELECT warranty_status
FROM warranty_records
WHERE warranty_status = 'active';

SELECT part_id, part_number
FROM hardware_parts
ORDER BY part_id;

SELECT part_id, quantity_in_stock
FROM inventory
WHERE quantity_in_stock < (SELECT setting_value FROM system_settings WHERE setting_name = 'default_reorder_level');

external_knowledge:
- 'Low-stock parts' refers to hardware parts with quantities below their reorder levels; 
- 'Recent performance checks' are those recorded within the last month; 
- 'Recent maintenance' refers to maintenance performed within the last year.

sql:
SELECT COUNT(*) AS active_warranty_count
FROM warranty_records
WHERE warranty_status = 'active';

SELECT part_id
FROM warranty_records
WHERE warranty_period = (SELECT MAX(warranty_period) FROM warranty_records);
